//
// Varlen backward (FAG::FAGVarlenOpt) kernel dispatch for v2, isolated from
// flash_api.cpp into per-dtype translation units under autogen/
// (varlen_bwd_dispatch_fp16.cpp / varlen_bwd_dispatch_bf16.cpp, generated by
// autogen/generate_kernels.py) so the 6 FAGVarlenOpt instantiations compile in
// parallel. (Always TND layout, so no layout axis is generated.)
//

#pragma once

#include <cstdint>
#include "acl/acl.h"

struct VarlenBwdLaunchArgs {
    uint32_t blockDim;
    aclrtStream aclStream;
    uint64_t fftsAddr;
    bool is_bf16;
    bool is_causal;
    uint8_t *qDevice;
    uint8_t *kDevice;
    uint8_t *vDevice;
    uint8_t *dOutDevice;
    uint8_t *attenMaskDevice;   // may be nullptr when is_causal is false
    uint8_t *softMaxLseDevice;
    uint8_t *outDevice;
    uint8_t *cuSeqQlenDevice;
    uint8_t *cuSeqKvlenDevice;
    uint8_t *dqDevice;
    uint8_t *dkDevice;
    uint8_t *dvDevice;
    uint8_t *workspaceDevice;
    uint8_t *tilingDevice;
};

// Per-dtype implementation, defined in autogen/varlen_bwd_dispatch_<dtype>.cpp.
// Each TU instantiates only its dtype's FAGVarlenOpt variants (causal / no-mask,
// plus the dump variant). (Always TND layout, so no layout axis is generated.)
template <typename DType>
void launch_varlen_bwd_impl(const VarlenBwdLaunchArgs &a);
